<template>
  <div class="playlist-container">
    <div class="top-wrap">
      <div class="img-wrap">
        <img :src="playlist.coverImgUrl" alt="" />
      </div>
      <div class="info-wrap">
        <p class="title">{{playlist.name}}</p>
        <div class="author-wrap">
          <img class="avatar" :src="avatarUrl" alt="" />
          <span class="name">{{nickname}}</span>
          <span class="time">{{playlist.createTime|filterDate}} 创建</span>
        </div>
        <div class="play-wrap">
          <span class="iconfont icon-circle-play"></span>
          <span class="text">播放全部</span>
        </div>
        <div class="tag-wrap">
          <span class="title">标签:</span>
          <ul>
            <li v-for="(item,i) in playlist.tags" :key="i">{{item}}</li>
          </ul>
        </div>
        <div class="desc-wrap">
          <span class="title">简介:</span>
          <span class="desc"
            >{{playlist.description}}</span
          >
        </div>
      </div>
    </div>
    <el-tabs v-model="activeIndex">
      <el-tab-pane label="歌曲列表" name="1">
        <table class="el-table playlit-table">
          <thead>
            <th></th>
            <th></th>
            <th>音乐标题</th>
            <th>歌手</th>
            <th>专辑</th>
            <th>时长</th>
          </thead>
          <tbody>
            <tr class="el-table__row" v-for="(item,i) in tracks" :key="item.id">
              <td>{{i+1}}</td>
              <td>
                <div class="img-wrap iconbofang">
                  <span class="iconfont icon-bofang1" @click="play(item.id)"></span>
                </div>
              </td>
              <td>
                <div class="song-wrap">
                  <div class="name-wrap">
                    <span>{{item.name}}</span>
                    <span class="iconfont" :class="{'icon-MV':item.mv ? 'icon-MV' : ''}" @click="playMv(item.mv)"></span>
                  </div>
                </div>
              </td>
              <td><span v-for="(items,i) in item.ar" :key="i">{{items.name}}</span></td>
              <td>{{item.al.name}}</td>
              <td>{{item.dt|getGapTime}}</td>
            </tr>
          </tbody>
        </table>
      </el-tab-pane>
      <el-tab-pane label="评论" name="2">
        <!-- 精彩评论 -->
        <div class="comment-wrap">
          <p class="title">精彩评论<span class="number">({{hotLen}})</span></p>
          <div class="comments-wrap">
            <div class="item" v-for="item in hotComments" :key="item.commentId">
              <div class="icon-wrap">
                <img :src="item.user.avatarUrl" alt="" />
              </div>
              <div class="content-wrap">
                <div class="content">
                  <span class="name">{{item.user.nickname}}：</span>
                  <span class="comment">{{item.content}}</span>
                </div>
                <div class="re-content" v-if="item.beReplied.length>0">
                  <span class="name">{{item.beReplied[0].user.nickname}}：</span>
                  <span class="comment">{{item.beReplied[0].content}}</span>
                </div>
                <div class="date">
                <div>{{item.time|filterDate2}}</div>
                <div class="dzinfo">
                  <span class="iconfont icon-dianzan1"></span>
                  <span class="dz">({{item.likedCount}})</span>
                </div>
              </div>
              </div>
            </div>
          </div>
        </div>
        <!-- 最新评论 -->
        <div class="comment-wrap">
          <p class="title">最新评论<span class="number">({{newLen}})</span></p>
          <div class="comments-wrap">
            <div class="item" v-for="item in comments" :key="item.commentId">
              <div class="icon-wrap">
                <img :src="item.user.avatarUrl" alt="" />
              </div>
              <div class="content-wrap">
                <div class="content">
                  <span class="name">{{item.user.nickname}}：</span>
                  <span class="comment">{{item.content}}</span>
                </div>
                <div class="re-content" v-if="item.beReplied.length>0">
                  <span class="name">{{item.beReplied[0].user.nickname}}：</span>
                  <span class="comment">{{item.beReplied[0].content}}</span>
                </div>
                <div class="date">{{item.time|filterDate}}</div>
              </div>
            </div>

          </div>
        </div>
        <!-- 分页器 -->
        <el-pagination
          @current-change="handleCurrentChange"
          background
          layout="prev, pager, next"
          :total="total"
          :current-page="page"
          :page-size="5"
        >
        </el-pagination>
      </el-tab-pane>
    </el-tabs>
  </div>
</template>

<script>
import music from "@/api/music"
export default {
  name: 'playlist',
  data() {
    return {
      activeIndex: '1',
      // 总条数
      total: 0,
      // 页码
      page: 1,
      playlist:{},
      avatarUrl:'',
      nickname:'',
      tracks:[],
      hotComments:[],
      comments:[],
      hotLen:'',
      newLen:''
    };
  },
  methods: {
    async playMv(mvid){
      this.$router.push('/mv?id='+mvid)
    },
    async play(id){
       const res = await music.playMusic({
        params:{
          id
        }
      })
      // console.log(res)
      this.$parent.$data.url = res.data[0].url
    },
    handleCurrentChange(val) {
      this.page = val
      this.getComment()
    },
    async goPlaylist(){
      const res = await music.getSongsDetail({
        params:{
          id:this.$route.query.id,
        }
      })
      // console.log(res)
      this.playlist = res.playlist
      this.avatarUrl = res.playlist.creator.avatarUrl
      this.nickname = res.playlist.creator.nickname
      this.tracks = res.playlist.tracks
    },
    async getComment(){
      const res = await music.getSongsComment({
        params:{
          id:this.$route.query.id,
          limit:10,
          offset:(this.page-1)*10
        }
      })
      // console.log(res)
      this.total = res.total
      this.hotComments = res.hotComments
      this.hotLen = res.hotComments ? res.hotComments.length:0
      this.comments = res.comments
      this.newLen = res.comments ? res.comments.length:0
    }
  },
  beforeRouteLeave(to, from, next){
    this.$parent.$data.url = ''
    next()
  },
  created(){
    this.goPlaylist()
    this.getComment()
  }
};
</script>

<style lang="scss" >
.playlist-container{
  .top-wrap{
    .info-wrap{
      .author-wrap{
        .name{
          color: #0CA2DE;
          font-size: 12px;
        }
        .time{
          font-size: 12px;
          color: #999999;
        }
      }
      .tag-wrap{
        ul{
          li{
            font-size: 12px;
            color: #777;
          }
        }
      }
    }
  }
  .iconbofang{
    display: flex;
    justify-content: center;
    align-items: center;
  }
  .icon-MV{
    margin-left: 5px;
    color: brown;
  }
  .date{
    display: flex;
    justify-content: space-between;
    align-items: center;
    .dzinfo{
      display: flex;
      align-items: center;
    }
    .icon-dianzan1{
      color: #FF962F;
      font-size: 20px;
      margin-right: 5px;
    }
    .dz{
      color: black;
    }
  }
}
</style>
